"use client";

import { useTranslations } from "next-intl";

/**
 * Related-articles list rendered at the foot of the article detail
 * view. Two data paths:
 *   - **Real mode** → `visitorNewsRelated` (BE pre-sorted by
 *     shared-taxonomy overlap, then `publishedAt` desc).
 *   - **Preview mode** → client-side overlap pass against
 *     `env.previewData.newsPostsById` so the dashboard mirrors what
 *     visitors would see without a BE round-trip.
 * Dummy / preview-without-overlap render nothing.
 */
export function RelatedNewsList({
  currentId,
  currentCategoryIds,
  currentTagIds,
  previewPostsById,
  visitorRelatedRaw,
  isDummy,
  onOpen,
}: {
  currentId: string;
  currentCategoryIds: string[];
  currentTagIds: string[];
  previewPostsById: Record<string, unknown> | undefined;
  visitorRelatedRaw: unknown;
  isDummy: boolean;
  onOpen: (id: string) => void;
}) {
  const t = useTranslations("news");

  const items: { id: string; title: string; coverImageUrl?: string }[] = (() => {
    if (isDummy) return [];

    // BE result wins when it's a non-empty array. The visitor surface's
    // `visitorNewsRelated` is the authoritative source — we prefer it
    // over the client-side overlap fallback even when both are reachable
    // (i.e. dashboard preview pane with prefetch AND a successful
    // visitor-side fetch).
    if (Array.isArray(visitorRelatedRaw) && visitorRelatedRaw.length > 0) {
      return visitorRelatedRaw
        .filter((x): x is Record<string, unknown> => !!x && typeof x === "object")
        .map((r) => {
          const cover =
            (r.coverImageUrl as Record<string, unknown> | undefined)?.url ??
            r.externalCoverImageUrl;
          return {
            id: String(r._id ?? r.id ?? ""),
            title: typeof r.title === "string" ? r.title : "",
            coverImageUrl: typeof cover === "string" ? cover : undefined,
          };
        })
        .filter((r) => r.id && r.title);
    }

    // Fallback: client-side overlap against the dashboard's prefetched
    // lookup. Skipped when the lookup is missing / empty, or when the
    // seed article has no taxonomy refs.
    if (
      previewPostsById &&
      Object.keys(previewPostsById).length > 0 &&
      (currentCategoryIds.length > 0 || currentTagIds.length > 0)
    ) {
      const seedCats = new Set(currentCategoryIds);
      const seedTags = new Set(currentTagIds);
      const scored: {
        id: string;
        title: string;
        coverImageUrl?: string;
        overlap: number;
        publishedAt: string;
      }[] = [];
      for (const [pid, raw] of Object.entries(previewPostsById)) {
        if (pid === currentId) continue;
        if (!raw || typeof raw !== "object") continue;
        const r = raw as Record<string, unknown>;
        const cats = Array.isArray(r.categories) ? r.categories : [];
        const tagsArr = Array.isArray(r.tags) ? r.tags : [];
        const idsFrom = (arr: unknown[]): Set<string> => {
          const s = new Set<string>();
          for (const x of arr) {
            if (x && typeof x === "object") {
              const xid = (x as { _id?: unknown; id?: unknown })._id ?? (x as { id?: unknown }).id;
              if (typeof xid === "string") s.add(xid);
            }
          }
          return s;
        };
        const catIds = idsFrom(cats);
        const tagIds = idsFrom(tagsArr);
        let overlap = 0;
        for (const c of catIds) if (seedCats.has(c)) overlap++;
        for (const ti of tagIds) if (seedTags.has(ti)) overlap++;
        if (overlap === 0) continue;
        const cover =
          (r.coverImageUrl as Record<string, unknown> | undefined)?.url ?? r.externalCoverImageUrl;
        scored.push({
          id: pid,
          title: typeof r.title === "string" ? r.title : "",
          coverImageUrl: typeof cover === "string" ? cover : undefined,
          overlap,
          publishedAt: typeof r.publishedAt === "string" ? r.publishedAt : "",
        });
      }
      scored.sort((a, b) =>
        b.overlap !== a.overlap
          ? b.overlap - a.overlap
          : b.publishedAt.localeCompare(a.publishedAt),
      );
      return scored
        .slice(0, 5)
        .map(({ id, title, coverImageUrl }) => ({ id, title, coverImageUrl }));
    }

    return [];
  })();

  if (items.length === 0) return null;

  return (
    <section className="mt-6">
      <p className="mb-2 text-xs font-semibold tracking-wide text-wx-fg-muted uppercase">
        {t("relatedTitle")}
      </p>
      <ul className="flex flex-col gap-2">
        {items.map((item) => (
          <li key={item.id}>
            <button
              type="button"
              onClick={() => onOpen(item.id)}
              className="flex w-full items-center gap-3 rounded-wx-lg bg-wx-bg-elevated px-3 py-2 text-left transition-colors hover:bg-wx-bg-elevated/80 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-wx-primary"
            >
              <span
                className="aspect-square w-12 shrink-0 rounded-wx-sm bg-cover bg-center"
                style={
                  item.coverImageUrl
                    ? { backgroundImage: `url(${item.coverImageUrl})` }
                    : { background: "linear-gradient(135deg, #1e1f21, #121314)" }
                }
                aria-hidden="true"
              />
              <span className="min-w-0 flex-1 truncate text-sm font-medium text-wx-fg">
                {item.title}
              </span>
            </button>
          </li>
        ))}
      </ul>
    </section>
  );
}
