/**
 * Normalised news-post projection + the extractor that produces it.
 * The same shape is rendered whether the source is mock data, the
 * dashboard's prefetch, or the visitor `visitorNewsPost({ id })` query.
 */
export interface NewsArticle {
  id: string;
  title: string;
  excerpt: string;
  contentMarkdown?: string;
  bodyFormat?: "html" | "markdown" | string;
  coverImageUrl?: string;
  coverGradient?: [string, string];
  publishedAt: string;
  upstreamUpdatedAt?: string | null;
  sourceUrl?: string;
  reactionCounts?: Record<string, number> | null;
  /** The visitor's own reaction slotIndex on this post's group (or null).
   *  Drives the reaction-bar active highlight; from the BE read query. */
  viewerReaction?: number | null;
  tags?: { slug: string; label: string }[];
  /** Used by client-side "related" computation in preview mode — the
   *  BE's `visitorNewsRelated` query handles this in real mode. We
   *  project the category id list so the preview can do an overlap
   *  count without hitting the visitor surface. */
  categoryIds?: string[];
  tagIds?: string[];
  /** Post byline — one or more authors (demo content; live news posts
   *  may not carry authors). */
  authors?: { _id: string; name: string; photo: { url: string } }[];
  /** Section label shown as an eyebrow above the title. */
  category?: { slug: string; label: string };
  /** Locale of THIS post — drives the active chip in the language
   *  selector. */
  locale?: string;
  /** Published locale variants (incl. self). The widget opens a
   *  variant by `id` (the visitor news lookup is id-keyed, so locale
   *  doesn't need to travel with it). */
  translations?: { id: string; locale: string }[];
}

/** Coerce the BE's raw post JSON (or an operator-side post row) into
 *  the `NewsArticle` shape. Defensive on every field — the same
 *  extractor handles `_id`-vs-`id` and the populated-Media cover vs
 *  the externally-pulled URL fallback. */
export function extractArticle(raw: unknown): NewsArticle | null {
  if (!raw || typeof raw !== "object") return null;
  const o = raw as Record<string, unknown>;
  const id = String(o._id ?? o.id ?? "");
  if (!id) return null;
  const mediaCover = (o.coverImageUrl as Record<string, unknown> | undefined)?.url;
  const externalCover = o.externalCoverImageUrl;
  const cover =
    typeof mediaCover === "string"
      ? mediaCover
      : typeof externalCover === "string"
        ? externalCover
        : undefined;
  const tags = Array.isArray(o.tags)
    ? (o.tags as unknown[])
        .map((t) => {
          if (!t || typeof t !== "object") return null;
          const slug = (t as { slug?: unknown }).slug;
          const label = (t as { label?: unknown }).label;
          if (typeof slug !== "string" || typeof label !== "string") {
            return null;
          }
          return { slug, label };
        })
        .filter((t): t is { slug: string; label: string } => !!t)
    : undefined;
  const idsFromObjList = (list: unknown): string[] | undefined => {
    if (!Array.isArray(list)) return undefined;
    const out: string[] = [];
    for (const x of list) {
      if (!x) continue;
      if (typeof x === "string") {
        out.push(x);
      } else if (typeof x === "object") {
        const xid = (x as { _id?: unknown; id?: unknown })._id ?? (x as { id?: unknown }).id;
        if (typeof xid === "string") out.push(xid);
      }
    }
    return out.length > 0 ? out : undefined;
  };
  // Published locale variants → `{ id, locale }`. The widget opens a
  // variant by id, so we only need those two fields.
  const translations = Array.isArray(o.translations)
    ? (o.translations as unknown[])
        .map((tr) => {
          if (!tr || typeof tr !== "object") return null;
          const tid = String(
            (tr as { _id?: unknown; id?: unknown })._id ?? (tr as { id?: unknown }).id ?? "",
          );
          const loc = (tr as { locale?: unknown }).locale;
          if (!tid || typeof loc !== "string") return null;
          return { id: tid, locale: loc };
        })
        .filter((tr): tr is { id: string; locale: string } => !!tr)
    : undefined;
  // Authors (operator byline) — `{ _id, name, photo: { url } }`. BE
  // posts may carry 0..N; demo content sets its own. The article view
  // renders up to 3 avatars + a "Written by …" line.
  const authors = Array.isArray(o.authors)
    ? (o.authors as unknown[])
        .map((a) => {
          if (!a || typeof a !== "object") return null;
          const name = (a as { name?: unknown }).name;
          if (typeof name !== "string") return null;
          const aid = (a as { _id?: unknown })._id;
          const url = (a as { photo?: { url?: unknown } }).photo?.url;
          return {
            _id: String(aid ?? name),
            name,
            photo: { url: typeof url === "string" ? url : "" },
          };
        })
        .filter((a): a is { _id: string; name: string; photo: { url: string } } => !!a)
    : undefined;
  return {
    id,
    title: typeof o.title === "string" ? o.title : "",
    excerpt: typeof o.excerpt === "string" ? o.excerpt : "",
    contentMarkdown: typeof o.contentMarkdown === "string" ? o.contentMarkdown : undefined,
    bodyFormat: typeof o.bodyFormat === "string" ? o.bodyFormat : undefined,
    coverImageUrl: cover,
    publishedAt: typeof o.publishedAt === "string" ? o.publishedAt : new Date().toISOString(),
    upstreamUpdatedAt: typeof o.upstreamUpdatedAt === "string" ? o.upstreamUpdatedAt : undefined,
    sourceUrl: typeof o.sourceUrl === "string" ? o.sourceUrl : undefined,
    reactionCounts: (o.reactionCounts as Record<string, number> | null | undefined) ?? null,
    viewerReaction: typeof o.viewerReaction === "number" ? o.viewerReaction : null,
    tags,
    authors,
    categoryIds: idsFromObjList(o.categories),
    tagIds: idsFromObjList(o.tags),
    locale: typeof o.locale === "string" ? o.locale : undefined,
    translations,
  };
}
