"use client";

import { ExternalLink } from "lucide-react";
import { useLocale, useTranslations } from "next-intl";
import { useState } from "react";
import { ScrollArea } from "@/components/ui/scroll-area";
import { getMockNewsItems } from "@/dummy";
import { looksLikeHtml } from "@/lib/detect-html";
import { ReactionSurface } from "@/lib/graphql/generated/types";
import {
  useVisitorNewsPostQuery,
  useVisitorNewsRelatedQuery,
} from "@/lib/graphql/queries/generated/news.generated";
import { useArticleTitleSink } from "@/lib/use-article-title-sink";
import { DEMO_LOCALES, useDemoTranslator } from "@/lib/use-demo-translator";
import { useWidgetConfig } from "@/lib/use-widget-config";
import { useWidgetEnv } from "@/lib/use-widget-env";
import { cn } from "@/lib/utils";
import { ArticleBody } from "../article-body";
import { LanguageSelector } from "../language-selector";
import { ReactionBar } from "../reaction-bar";
import { formatNewsEditedAgo, isNewsPostEdited } from "../tabs/news-tab";
import { extractArticle, type NewsArticle } from "./helpers";
import { RelatedNewsList } from "./related-news-list";

interface NewsArticleViewProps {
  id: string;
  isDummy: boolean;
  /** Tap a related-article tile → swap the view to that post. The
   *  shell wires this to the same `news-article` route swap the news
   *  card click already uses, so back-navigation lands on the feed. */
  onOpenRelated?: (id: string) => void;
  /** Title sink for the widget shell's sticky header. Called with
   *  the article title once data resolves, and with `null` on
   *  unmount to clear the header back to the parent tab's name. */
  onTitleResolved?: (title: string | null) => void;
}

/**
 * News post detail view. Hydration order:
 *   1. **Dummy mode** → match `getMockNewsItems()` by id.
 *   2. **Preview mode** → use `env.previewData.newsPostsById[id]` (the
 *      dashboard prefetched the full post via its operator GraphQL).
 *   3. **Live mode** → call `useVisitorNewsPostByIdQuery`.
 *
 * Body renders via `react-markdown` when `bodyFormat` is markdown (or
 * unset — markdown is the default). HTML-format posts route through
 * `dangerouslySetInnerHTML` since the BE ingest already sanitises them.
 *
 * Back navigation lives on the shell's `TabTitleHeader` — this
 * component just owns the scroll surface.
 */
export function NewsArticleView({
  id,
  isDummy,
  onOpenRelated,
  onTitleResolved,
}: NewsArticleViewProps) {
  const t = useTranslations("news");
  const tDemo = useTranslations("demo");
  const locale = useLocale();
  const env = useWidgetEnv();
  const { config } = useWidgetConfig();
  const showRelated = config.messenger?.showRelatedNews ?? true;
  const showReactionCounts = config.messenger?.showReactionCounts ?? true;

  // Article-scoped language switch in demo mode — defaults to the widget
  // locale, changed by the below-article dropdown without touching the
  // widget's own locale.
  const [demoLocale, setDemoLocale] = useState(locale);
  const demoT = useDemoTranslator(demoLocale, tDemo);

  // Preview takes priority over the live query — the dashboard has
  // already loaded the full post, so we skip the visitor round-trip.
  const previewRaw = !isDummy ? env.previewData?.newsPostsById?.[id] : null;
  const hasPreview = !!previewRaw;

  const { data, loading } = useVisitorNewsPostQuery({
    variables: { args: { id, locale } },
    skip: isDummy || hasPreview || !id,
  });

  // Related posts — visitor surface in real mode. Preview mode falls
  // back to a client-side overlap pass against the prefetched feed
  // (BE-equivalent: shared category-or-tag id count, then publishedAt
  // desc as tiebreaker) so the dashboard pane mirrors what visitors
  // would see.
  const { data: relatedData } = useVisitorNewsRelatedQuery({
    // Pass the widget's active locale (not the article's) so related
    // follows the reader's language — fixes wrong-language related when
    // reading a fallback (default-locale) article.
    variables: { postId: id, limit: 5, locale },
    skip: isDummy || hasPreview || !id || !showRelated,
  });

  const mockArticle = isDummy ? (getMockNewsItems(demoT).find((n) => n.id === id) ?? null) : null;

  const article: NewsArticle | null = mockArticle
    ? {
        id: mockArticle.id,
        title: mockArticle.title,
        excerpt: mockArticle.excerpt,
        contentMarkdown: mockArticle.contentMarkdown,
        // `bodyFormat` stays markdown; HTML demo bodies are auto-detected
        // by `looksLikeHtml` below and routed through `ArticleHtml`.
        bodyFormat: "markdown",
        coverImageUrl: mockArticle.coverImageUrl,
        coverGradient: mockArticle.coverGradient,
        publishedAt: mockArticle.publishedAt,
        upstreamUpdatedAt: mockArticle.upstreamUpdatedAt,
        tags: mockArticle.tags,
        authors: mockArticle.authors,
        category: mockArticle.category,
        // Demo: article shown in the selected demo locale.
        locale: demoLocale,
      }
    : hasPreview
      ? extractArticle(previewRaw)
      : extractArticle(data?.visitorNewsPost);

  // Surface the title up to the widget shell's sticky header (swaps
  // "News" → article name). See `useArticleTitleSink` for why the
  // mount/unmount ownership is the single source of truth.
  useArticleTitleSink(article?.title, onTitleResolved);

  if (!article) {
    if (loading) {
      // Article-shaped skeleton — see `NewsArticleSkeleton` below
      // for the structure. Same `animate-pulse` opacity-only loop
      // as the help-article skeleton so layouts stay consistent.
      return <NewsArticleSkeleton />;
    }
    return (
      <div className="flex flex-1 items-center justify-center px-6 py-12 text-center">
        <p className="text-sm text-wx-fg-muted">{t("articleNotFound")}</p>
      </div>
    );
  }

  const fallbackGradient: [string, string] = article.coverGradient ?? ["#1e1f21", "#121314"];

  return (
    <ScrollArea className="flex-1">
      {/* Plain `<div>` — the widget shell's route slide already
          covers the enter animation. Stacking a second opacity+y
          keyframe on top thrashed the main thread during article
          navigation: panel width animating + route sliding + body
          fading + Apollo query rendering, all on the same frame.
          The route slide alone is enough and visibly snappier. */}
      <div className="flex flex-col">
        <div
          className={cn("relative w-full")}
          style={{
            aspectRatio: "16 / 9",
            background: article.coverImageUrl
              ? `url(${article.coverImageUrl}) center/cover`
              : `linear-gradient(135deg, ${fallbackGradient[0]}, ${fallbackGradient[1]})`,
          }}
          aria-hidden="true"
        />
        <div className="flex flex-col gap-3 px-5 pt-5 pb-12">
          {article.category && (
            <p className="text-[11px] font-semibold tracking-[0.14em] text-wx-primary uppercase">
              {article.category.label}
            </p>
          )}
          <p className="flex items-center gap-2 text-xs text-wx-fg-subtle">
            <span>
              {new Date(article.publishedAt).toLocaleDateString(locale, {
                month: "long",
                day: "numeric",
                year: "numeric",
              })}
            </span>
            {isNewsPostEdited(article) && article.upstreamUpdatedAt && (
              <span
                className="rounded-full bg-wx-bg-elevated px-1.5 py-0.5 text-[10px] font-medium text-wx-fg-muted"
                title={new Date(article.upstreamUpdatedAt).toLocaleString(locale)}
              >
                {t("editedAt", {
                  when: formatNewsEditedAgo(article.upstreamUpdatedAt),
                })}
              </span>
            )}
          </p>
          <h2 className="text-2xl leading-tight font-bold text-wx-fg">{article.title}</h2>
          {article.authors && article.authors.length > 0 && (
            <p className="flex items-center gap-2 text-xs text-wx-fg-muted">
              <span className="flex -space-x-1.5">
                {article.authors.slice(0, 3).map((a) => (
                  <span
                    key={a._id}
                    className="h-5 w-5 overflow-hidden rounded-full bg-wx-bg-elevated ring-1 ring-wx-bg"
                    aria-hidden="true"
                  >
                    {/* biome-ignore lint/performance/noImgElement: tiny avatar, no LCP impact */}
                    <img src={a.photo.url} alt="" className="h-full w-full object-cover" />
                  </span>
                ))}
              </span>
              <span>
                {t("writtenBy", { names: article.authors.map((a) => a.name).join(", ") })}
              </span>
            </p>
          )}
          {article.tags && article.tags.length > 0 && (
            <div className="flex flex-wrap gap-1">
              {article.tags.map((tag) => (
                <span
                  key={tag.slug}
                  className="rounded-full bg-wx-bg-elevated px-2 py-0.5 text-[11px] font-medium text-wx-fg-muted"
                >
                  {tag.label}
                </span>
              ))}
            </div>
          )}
          {article.excerpt && (
            <p className="text-base leading-relaxed text-wx-fg-muted">{article.excerpt}</p>
          )}
          {article.contentMarkdown && (
            <ArticleBody
              content={article.contentMarkdown}
              // BE-stamped `bodyFormat` wins when set explicitly to
              // `html` (RSS `<content:encoded>`), otherwise we sniff
              // the content — TipTap-authored native posts save with
              // the default `markdown` despite producing HTML.
              isHtml={article.bodyFormat === "html" || looksLikeHtml(article.contentMarkdown)}
              markdownMarginClass="mt-3"
            />
          )}
          {article.sourceUrl && (
            <a
              href={article.sourceUrl}
              target="_blank"
              rel="noopener noreferrer"
              className="mt-4 flex items-center justify-center gap-1.5 text-xs text-wx-primary underline underline-offset-2 transition-opacity hover:opacity-80"
            >
              <ExternalLink size={12} />
              <span>{t("readOriginal")}</span>
            </a>
          )}

          {showRelated && (
            <RelatedNewsList
              currentId={article.id}
              currentCategoryIds={article.categoryIds ?? []}
              currentTagIds={article.tagIds ?? []}
              previewPostsById={!isDummy ? env.previewData?.newsPostsById : undefined}
              visitorRelatedRaw={relatedData?.visitorNewsRelated}
              isDummy={isDummy}
              onOpen={onOpenRelated ?? (() => {})}
            />
          )}

          {/* Reactions bar — unified surface; operator-curated emoji
              palette via the News reactions settings. Defaults seed
              to 🎉 / ❤️ / 👍 NEUTRAL so the row never renders empty
              before an operator customises. */}
          {article.id && (
            <ReactionBar
              surface={ReactionSurface.NEWS}
              itemId={article.id}
              reactionCounts={article.reactionCounts ?? null}
              viewerReaction={article.viewerReaction ?? null}
              // All locale variants of this post — a reaction is per-group,
              // so keep their cached counts/highlight in sync.
              groupItemIds={[article.id, ...(article.translations ?? []).map((tr) => tr.id)]}
              isDummy={isDummy}
              showCounts={showReactionCounts}
              className="mt-6"
            />
          )}

          {/* Language switcher — in demo it swaps the post content in
              place (article-scoped); in live mode it opens the chosen
              variant by id. Hidden when the post exists in one language. */}
          <LanguageSelector
            currentLocale={isDummy ? demoLocale : (article.locale ?? locale)}
            locales={
              isDummy ? [...DEMO_LOCALES] : (article.translations ?? []).map((tr) => tr.locale)
            }
            onSelect={
              isDummy
                ? (loc) => setDemoLocale(loc)
                : (loc) => {
                    const target = (article.translations ?? []).find((tr) => tr.locale === loc);
                    if (target) onOpenRelated?.(target.id);
                  }
            }
            className="mt-6"
          />
        </div>
      </div>
    </ScrollArea>
  );
}

/**
 * Loading state for the news article view. Mirrors the real
 * article's geometry: a 16:9 cover block, then a 2-line title and
 * body lines, all `animate-pulse`-driven (opacity only, no layout
 * thrash). Sits inside a `ScrollArea` so the surrounding shell's
 * scrollbar / chrome doesn't shift between skeleton and real
 * content.
 */
function NewsArticleSkeleton() {
  return (
    <ScrollArea className="flex-1">
      <div className="flex flex-col" aria-busy="true" aria-live="polite">
        {/* Cover block — 16:9 to match the actual hero image. */}
        <div className="w-full animate-pulse bg-wx-bg-elevated" style={{ aspectRatio: "16 / 9" }} />
        <div className="px-5 pt-5 pb-12">
          {/* Title — two lines of varying width. */}
          <div className="animate-pulse space-y-2.5">
            <div className="h-5 w-3/4 rounded-md bg-wx-bg-elevated" />
            <div className="h-5 w-1/2 rounded-md bg-wx-bg-elevated" />
          </div>
          {/* Date / source line. */}
          <div className="mt-4 flex items-center gap-2 animate-pulse">
            <div className="h-3 w-24 rounded-md bg-wx-bg-elevated" />
          </div>
          {/* Body — six lines of varying length for the paragraph
              cadence the article will paint into. */}
          <div className="mt-6 space-y-2.5 animate-pulse">
            {["w-full", "w-11/12", "w-10/12", "w-full", "w-9/12", "w-7/12"].map((w, i) => (
              // biome-ignore lint/suspicious/noArrayIndexKey: static order-stable skeleton with duplicate width values — index is the only stable key
              <div key={i} className={cn("h-3 rounded-md bg-wx-bg-elevated", w)} />
            ))}
          </div>
        </div>
      </div>
    </ScrollArea>
  );
}
